-- Redgum Shire Council: own multi-site demo assessment (generated).
-- Safe to run once; ON CONFLICT DO NOTHING makes re-runs no-ops.
do $$
declare v_org uuid; v_user uuid; v_site uuid;
begin
  select id into v_org from organisations where name ilike '%redgum%' order by created_at limit 1;
  if v_org is null then raise exception 'Redgum org not found - no organisation name contains redgum'; end if;
  select user_id into v_user from organisation_memberships where organisation_id = v_org and status = 'active' order by created_at limit 1;
  update organisations set jurisdiction = 'AU-SA' where id = v_org;

  -- ===== Central Library =====
  select id into v_site from sites where organisation_id = v_org and name = 'Central Library';
  values ('seed-redgum-central-library','1.1','1.1','completed','mixed','{"doingWell":["Do you clearly state limitations or barriers that still exist?","Do you invite feedback about the accuracy of your accessibility information?","Do customers have a way to ask accessibility questions without calling?"],"priorityActions":[{"questionId":"1.1-F-1","questionText":"Do you have accessibility information available for customers before they visit?","action":"Review your current accessibility information for completeness. Ensure it covers physical access, sensory environment, communication supports, and practical visit-planning details.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"1.1-D-9","questionText":"Is your accessibility information consistent across all platforms?","action":"Identify and resolve inconsistencies in your accessibility information across platforms. Create a single source of truth document that all platform updates reference.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.1-F-5","questionText":"Can customers contact you in a variety of ways to ask accessibility questions before visiting?","action":"Provide multiple ways for customers to ask accessibility questions before visiting, such as phone, email, online chat, contact form, and social media messaging. Relying on a single channel excludes customers who cannot use that method.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-F-6","questionText":"Do staff know how to confidently respond to accessibility enquiries?","action":"Prepare a reference guide of common accessibility enquiries and accurate answers so staff can respond confidently. Include details like accessible parking location, entrance type, available supports, and who to escalate to when unsure.","priority":"high","timeframe":"30-90 days"}],"areasToExplore":["Do you proactively invite accessibility questions?"],"professionalReview":[]}'::jsonb,now() - interval '60 days',now() - interval '58 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','1.2','1.2','completed','mixed','{"doingWell":["Can all website content be accessed using only a keyboard (no mouse required)?","When using the keyboard, can you always see which element is currently focused?","Do images on your website have alt text or image descriptions?"],"priorityActions":[{"questionId":"1.2-1-3","questionText":"Is your website text easy to read with good contrast between text and background?","action":"Measure all text-to-background colour combinations using a contrast checker and update any that fall below 4.5:1 for normal text or 3:1 for large text per WCAG 2.2 SC 1.4.3.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.2-1-5c","questionText":"Are buttons and links easy to tap on mobile without accidentally hitting the wrong thing?","action":"Most tap targets are adequate. Review closely spaced links, small icon buttons, and inline text links that may be too small for motor-impaired users.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":["Can users resize text or zoom the page without losing content or functionality?","Do forms on your website (contact forms, enquiry forms, newsletter signups) have clear labels and instructions?"],"professionalReview":[]}'::jsonb,now() - interval '59 days',now() - interval '57 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','2.1','2.1','completed','mixed','{"doingWell":["Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?","Is the path from accessible parking to the entrance smooth and level?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Accessible parking spaces exist but may not fully comply. Audit each space against AS/NZS 2890.6 for correct dimensions (min 2400mm wide, 5400mm long with shared area), signage, and surface condition.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"Regrade or modify the drop-off zone to provide a firm, level surface flush with the adjacent footpath. Install a kerb ramp or dropped kerb per AS 1428.1 Cl 10 if there is a level change between the roadway and the path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6b","questionText":"If the accessible route differs from the main pedestrian path, is it clearly signed?","action":"Some signage exists but the divergence point is not clearly marked. Add prominent ISA signage at the exact point of divergence and at intervals along the alternative route until it reaches the entrance.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-7","questionText":"Do staff know how to direct customers to accessible parking and entry points?","action":"Some staff are aware but knowledge is inconsistent. Standardise training so all customer-facing staff can confidently direct visitors to accessible parking and entry points. Consider a printed quick-reference card for new team members.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '58 days',now() - interval '56 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','2.2','2.2','completed','mixed','{"doingWell":["Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","If there is a ramp, does it have handrails on both sides?","Does the ramp feel too steep for someone using a wheelchair or walking frame?"],"priorityActions":[{"questionId":"2.2-D-23","questionText":"If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","action":"Handrails are present but may be on one side only or not fully compliant. Install a second handrail where missing and check that both meet AS 1428.1 for height, extension, graspability, and continuity.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-25","questionText":"Are the stair or step risers enclosed (no open gaps between steps)?","action":"Enclose all open risers on entrance stairs. Open risers create a catch hazard for cane tips, prosthetic feet, and shoe toes. Install riser panels or replace the staircase with a compliant design per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-26","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?","action":"Install tactile ground surface indicators (TGSIs) at the top and bottom of entrance stairs. Warning TGSIs (truncated domes) must extend 600mm from the stair nosing across the full width, with min 30% luminance contrast, per AS 1428.4.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-31","questionText":"Is the entrance lift large enough for a wheelchair user, with at least a 900mm door opening?","action":"The lift partially meets requirements but may fall short on door width or internal dimensions. Measure against AS 1735.12 minimums (900mm door, 1400 x 1100mm cabin) and plan modifications for any non-compliant dimension.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '57 days',now() - interval '55 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','3.1','3.1','completed','strong','{"doingWell":["Are tables and counters at accessible heights for wheelchair users?","Can furniture be rearranged to accommodate different needs?","Are aisles and pathways between furniture wide enough throughout the space?"],"priorityActions":[{"questionId":"3.1-1-1","questionText":"Is there a variety of seating options (with arms, without arms, different heights)?","action":"Some variety exists. Add seats with armrests for people who need support standing up, and ensure at least some seating has firm cushions and higher seat heights.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"3.1-1-2","questionText":"Is there space for wheelchair users alongside seated companions?","action":"Designate clear wheelchair spaces (minimum 800mm x 1300mm per AS 1428.1) adjacent to standard seating so wheelchair users can sit alongside companions.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '56 days',now() - interval '54 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values (v_org,v_site,'3.1','3.1','seed-run-redgum-central-library-3.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','mixed','{"doingWell":["Is there space for wheelchair users alongside seated companions?","Are aisles and pathways between furniture wide enough throughout the space?","Does furniture contrast visually with the floor, making it easy for people with low vision to navigate?"],"priorityActions":[{"questionId":"3.1-1-1","questionText":"Is there a variety of seating options (with arms, without arms, different heights)?","action":"Provide seating with different arm, height, and depth options so people with varying mobility, size, and support needs can find comfortable seating.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-1-3","questionText":"Are tables and counters at accessible heights for wheelchair users?","action":"Some accessible-height surfaces exist. Audit all service counters, dining tables, and workstations and ensure accessible options are available in every area.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"3.1-1-4","questionText":"Can furniture be rearranged to accommodate different needs?","action":"Replace or supplement fixed furniture with movable options so staff can rearrange layouts for wheelchair users, mobility aid users, or service animals.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-6","questionText":"Can service animals be accommodated at seating?","action":"Ensure all seating areas can accommodate assistance animals under the DDA 1992. Provide adequate floor space beside or under tables, avoid blocking emergency exits, and ensure staff are aware that recognised assistance animals must not be refused entry.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,'[{"questionId":"3.1-1-1","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-2","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-3","answer":"partially","partialDescription":"Large-print materials available on request but not routinely offered.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-4","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-2","answer":"yes","notes":"Verified with the venue coordinator.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-6","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-8","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-9","answer":"partially","partialDescription":"Hearing loop installed at the main desk only, not in meeting rooms.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-14","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"}]'::jsonb,v_user)
  on conflict (run_id) do nothing;
  values ('seed-redgum-central-library','3.5','3.5','completed','strong','{"doingWell":["Is signage clear, with good contrast and readable font sizes?","Are signs placed at consistent heights and locations?","Are accessible facilities (toilets, lifts) clearly signed?"],"priorityActions":[{"questionId":"3.5-D-6","questionText":"Are emergency exit signs clearly visible and illuminated?","action":"Some exit signs are compliant but coverage is incomplete. Audit all escape routes and add illuminated signs where missing, ensuring visibility from all points on the accessible path of travel.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '55 days',now() - interval '53 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.1','4.1','completed','strong','{"doingWell":["Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","Are your staff trained to receive calls via the National Relay Service (NRS)?","Do you capture and use customer communication preferences (preferred contact method, format needs)?"],"priorityActions":[{"questionId":"4.1-PC-6","questionText":"Do staff know what AAC (Augmentative and Alternative Communication) devices are and how to interact with users?","action":"Basic awareness exists. Deepen training to cover different AAC types and practical interaction techniques, including allowing extra time and directing conversation to the customer (not their support person).","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-8","questionText":"Do you offer written confirmation or follow-up after important phone or in-person conversations?","action":"Written follow-ups happen sometimes. Make them standard practice for all significant interactions, not just on request.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '54 days',now() - interval '52 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.2','4.2','completed','mixed','{"doingWell":["Do you have a process for customers to request assistance before arriving?","Are staff trained in various communication strategies?","Is there a clear process for handling accessibility complaints or feedback?"],"priorityActions":[{"questionId":"4.2-F-2","questionText":"Do staff know how to welcome and assist customers with assistance animals?","action":"Some staff are aware. Ensure all staff (including casuals and contractors) know that assistance animals must be admitted, cannot be questioned, and must not be separated from their handler.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"4.2-F-3","questionText":"Do staff feel confident communicating with customers who have different needs?","action":"Staff have some confidence but gaps remain. Identify specific areas of uncertainty through a staff survey and provide targeted training to build comfort across all disability types.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-9","questionText":"Are staff trained to offer assistance without being condescending or over-helpful?","action":"Train staff to offer assistance respectfully: ask \"Can I help with anything?\" rather than assuming, speak directly to the customer (not their companion), and follow the customer''s lead on what help they want.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '53 days',now() - interval '51 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.3','4.3','completed','strong','{"doingWell":["Can customers easily modify bookings if their needs change?","Are payment terminals positioned at accessible heights?","Can staff bring payment terminals to customers if needed?"],"priorityActions":[{"questionId":"4.3-1-4","questionText":"Is there flexibility in cancellation policies for disability-related changes?","action":"Introduce flexible cancellation and modification terms for disability-related changes (e.g., health flare-ups, carer unavailability) and communicate this policy clearly during booking.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '52 days',now() - interval '50 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','5.3','5.3','completed','strong','{"doingWell":["Is disability awareness included in staff onboarding?","Is disability training refreshed regularly?","Do staff have access to resources about accessibility and disability?"],"priorityActions":[],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '51 days',now() - interval '49 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Regional Art Gallery =====
  select id into v_site from sites where organisation_id = v_org and name = 'Regional Art Gallery';
  values ('seed-redgum-regional-art-gallery','1.1','1.1','completed','strong','{"doingWell":["Do you have accessibility information available for customers before they visit?","Do you invite feedback about the accuracy of your accessibility information?","Can customers contact you in a variety of ways to ask accessibility questions before visiting?"],"priorityActions":[{"questionId":"1.1-D-9","questionText":"Is your accessibility information consistent across all platforms?","action":"Audit all platforms where your accessibility information appears and ensure consistency. Discrepancies between your website, Google listing, social media, and third-party platforms create confusion and erode trust.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-D-8a","questionText":"Is your transport information specific to accessibility needs?","action":"Add more accessibility-specific detail to your transport information. Include practical information such as surface types, gradients, distances from transport stops, and accessible features at nearby stations or stops.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '50 days',now() - interval '48 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','2.1','2.1','completed','mixed','{"doingWell":["Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?","Is the drop-off zone level and easy to access from the footpath?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"Widen the path to at least 1000mm clear width (1200mm preferred, 1800mm at passing points) per AS 1428.1 Cl 7. Remove any obstructions that narrow the effective width, including overhanging vegetation, bins, or signage.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-6a","questionText":"Is there wayfinding signage from the parking area to the entrance?","action":"Wayfinding is partially in place but has gaps. Walk the route from each accessible bay to the entrance and add signage at every decision point or change of direction where the next sign is not already visible.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '49 days',now() - interval '47 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','2.2','2.2','completed','mixed','{"doingWell":["If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","Are the stair or step risers enclosed (no open gaps between steps)?","Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?"],"priorityActions":[{"questionId":"2.2-D-29","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the ramp?","action":"TGSIs are present at one end but missing at the other. Install compliant warning TGSIs at both the top and bottom of the ramp, ensuring full-width coverage and correct 600mm depth.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-31","questionText":"Is the entrance lift large enough for a wheelchair user, with at least a 900mm door opening?","action":"Ensure the entrance lift has a minimum internal dimension of 1400mm deep x 1100mm wide and a door clear opening of at least 900mm per AS 1735.12. If the current lift does not meet these minimums, plan for replacement or modification.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-13","questionText":"Is the door threshold level? (The maximum height is 13mm)","action":"The threshold is close to compliant but slightly raised or uneven. Measure precisely; if between 5-13mm, bevel the edges. If over 13mm, install a compliant threshold or micro-ramp to eliminate the step.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-18","questionText":"Are entrance mats and surface changes flush and secure?","action":"Secure all entrance mats flush with the surrounding floor surface (max 3mm lip). Replace any mats that curl at edges, have thick pile that impedes wheels, or sit in a recessed frame with raised edges. Ensure surface changes do not create trip hazards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Do the stair or step edges have contrasting nosing strips so each step is clearly visible?"],"professionalReview":[]}'::jsonb,now() - interval '48 days',now() - interval '46 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.1','3.1','completed','mixed','{"doingWell":["Can furniture be rearranged to accommodate different needs?","Are aisles and pathways between furniture wide enough throughout the space?","Can service animals be accommodated at seating?"],"priorityActions":[{"questionId":"3.1-1-1","questionText":"Is there a variety of seating options (with arms, without arms, different heights)?","action":"Some variety exists. Add seats with armrests for people who need support standing up, and ensure at least some seating has firm cushions and higher seat heights.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"3.1-1-2","questionText":"Is there space for wheelchair users alongside seated companions?","action":"Designate clear wheelchair spaces (minimum 800mm x 1300mm per AS 1428.1) adjacent to standard seating so wheelchair users can sit alongside companions.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.1-1-3","questionText":"Are tables and counters at accessible heights for wheelchair users?","action":"Some accessible-height surfaces exist. Audit all service counters, dining tables, and workstations and ensure accessible options are available in every area.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '47 days',now() - interval '45 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.3','3.3','completed','strong','{"doingWell":["Does lighting support comfortable navigation and sensory regulation?","Are there quiet or reset spaces available for people who need a sensory break?","Is background noise at a level that allows conversation?"],"priorityActions":[{"questionId":"3.3-1-6","questionText":"Are sensory kits or supports available for customers and visitors?","action":"Create sensory support kits (noise-reducing headphones, fidget tools, sunglasses, communication cards) available for loan at reception or entry points.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.3-D-5","questionText":"Is background music volume adjustable or able to be managed?","action":"Music is manageable in some zones. Extend zone controls so staff can adjust or mute music in key communication areas (service counters, information points) when needed.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '46 days',now() - interval '44 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.5','3.5','completed','mixed','{"doingWell":["Are accessible facilities (toilets, lifts) clearly signed?","Would a first-time visitor be able to navigate independently?","Is there clear signage on the approach to your venue and at the entrance?"],"priorityActions":[{"questionId":"3.5-1-1","questionText":"Is signage clear, with good contrast and readable font sizes?","action":"Main signs are clear. Review smaller directional signs, room labels, and temporary signage for consistent contrast, sizing, and readability.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-2","questionText":"Are signs placed at consistent heights and locations?","action":"Most signs are consistently placed. Audit newer or temporary signage that may have been installed at non-standard heights or inconsistent locations.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"3.5-D-3","questionText":"Is there directional signage at key decision points throughout the venue?","action":"Directional signs exist at some decision points. Map the visitor journey and identify all decision points where signage is needed, prioritising routes to toilets, exits, and lifts.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"3.5-D-6","questionText":"Are emergency exit signs clearly visible and illuminated?","action":"Some exit signs are compliant but coverage is incomplete. Audit all escape routes and add illuminated signs where missing, ensuring visibility from all points on the accessible path of travel.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '45 days',now() - interval '43 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
