  -- ===== Visitor Information Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Visitor Information Centre';
  values ('seed-redgum-visitor-information-centre','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Do you invite feedback about the accuracy of your accessibility information?","Can customers contact you in a variety of ways to ask accessibility questions before visiting?"],"priorityActions":[{"questionId":"1.1-D-9","questionText":"Is your accessibility information consistent across all platforms?","action":"Audit all platforms where your accessibility information appears and ensure consistency. Discrepancies between your website, Google listing, social media, and third-party platforms create confusion and erode trust.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-D-5b","questionText":"Do customers have a way to ask accessibility questions without calling?","action":"Review your non-phone contact options to ensure they are genuinely accessible and responsive. Confirm that enquiries via these channels receive the same quality and speed of response as phone calls.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.1-F-6","questionText":"Do staff know how to confidently respond to accessibility enquiries?","action":"Review the most common accessibility enquiries your team receives and ensure accurate, up-to-date answers are documented and easy for staff to access during customer interactions.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":["Do you clearly state limitations or barriers that still exist?","Is your transport information specific to accessibility needs?"],"professionalReview":[]}'::jsonb,now() - interval '43 days',now() - interval '41 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','1.4','1.4','completed','mixed','{"doingWell":["Do you include alt text or image descriptions when posting images on social media?","Can users control video playback using keyboard, screen readers, or other assistive technology?","Do you verify that alt text is preserved when reposting or sharing content?"],"priorityActions":[{"questionId":"1.4-DD-3f","questionText":"Do you add alt text or image descriptions to each image in carousel or multi-image posts?","action":"Review your multi-image and carousel posts to ensure every image has individual alt text, not just the first image.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.4-PC-6","questionText":"Does your video and social media content include diverse representation, including people with disability?","action":"Include authentic representation of people with disability in your video and social media content. Feature people with visible and non-visible disabilities as customers, participants, and community members, not just in accessibility-specific contexts.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.4-DD-1d","questionText":"Are captions easy to read (good contrast, appropriate size, clear font)?","action":"Improve caption readability by ensuring sufficient contrast between caption text and background, using an appropriately sized font, and selecting a clear, sans-serif typeface. Consider using a semi-transparent background behind captions for variable video backgrounds.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.4-DD-3e","questionText":"When you add text over images, does it have sufficient contrast to be readable?","action":"Audit your image-based content for text contrast issues. Use a contrast checker tool and apply semi-transparent backgrounds or solid colour bars behind text overlays.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '42 days',now() - interval '40 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','1.5','1.5','completed','mixed','{"doingWell":["Do you use respectful, person-centred language when referring to people with disability?","Do you actively communicate your commitment to accessibility (not just list features)?","Do you let customers know that information is available in alternative formats?"],"priorityActions":[{"questionId":"1.5-PC-3","questionText":"Is your accessibility language welcoming and customer-focused?","action":"Reframe your accessibility information to focus on what IS available rather than what is not. For example, \"Our venue has step-free access and an accessible bathroom\" is more welcoming than \"We cannot accommodate wheelchairs upstairs.\"","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.5-PC-4","questionText":"Is accessibility information easy to find on your website (not buried or hidden)?","action":"Improve the prominence of your accessibility information. Test with customers to confirm they can find it within two clicks from the homepage without needing to use site search.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"1.5-PC-5","questionText":"Does your accessibility information cover practical details customers need to plan their visit?","action":"Identify gaps in your accessibility information by comparing it against common customer needs. Prioritise adding details about physical access, toilets, and the sensory environment.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.5-DD-1a","questionText":"Have you tested your website content for readability level?","action":"Test your website content for readability level using tools such as the Flesch-Kincaid readability score or Hemingway Editor. Aim for a reading level of Year 8 or below for general public content.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":["Do you include visual content (photos, videos, virtual tours) to help customers understand your venue?"],"professionalReview":[]}'::jsonb,now() - interval '41 days',now() - interval '39 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','2.1','2.1','completed','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Is the drop-off zone level and easy to access from the footpath?","Is there directional signage on the road approach directing visitors to accessible parking?"],"priorityActions":[{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Some accessible spaces are close to the entrance but others are not. Review the layout and prioritise relocating any distant spaces to minimise the travel distance to the main entrance.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"The path is mostly smooth but has uneven sections or minor level changes. Identify and remediate all trip hazards, cracks, or loose surfaces. Ensure the entire route meets AS 1428.1 requirements for a continuous accessible path.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"Widen the path to at least 1000mm clear width (1200mm preferred, 1800mm at passing points) per AS 1428.1 Cl 7. Remove any obstructions that narrow the effective width, including overhanging vegetation, bins, or signage.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '40 days',now() - interval '38 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','4.1','4.1','completed','mixed','{"doingWell":["Are staff trained to communicate patiently with people who have speech disabilities, strong accents, or use AAC devices?","Do staff know what AAC (Augmentative and Alternative Communication) devices are and how to interact with users?","Is there a quiet space available for communication with customers who need a calmer environment?"],"priorityActions":[{"questionId":"4.1-PC-1","questionText":"Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","action":"Provide at least two non-phone contact options (e.g., email, live chat, SMS, online form). Under the DDA 1992, services must be accessible to people who cannot use voice telephone.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.1-PC-2","questionText":"Are your staff trained to receive calls via the National Relay Service (NRS)?","action":"Some staff are NRS-aware. Extend training to all customer-facing roles and include NRS call handling in onboarding materials.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-4","questionText":"Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","action":"Response times are partially aligned. Review SLAs for all channels and bring non-phone response times in line with phone benchmarks.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you capture and use customer communication preferences (preferred contact method, format needs)?","Do you offer written confirmation or follow-up after important phone or in-person conversations?"],"professionalReview":[]}'::jsonb,now() - interval '39 days',now() - interval '37 days',v_org,v_site,v_user,v_user)
