  -- ===== Aquatic & Leisure Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Aquatic & Leisure Centre';
  values ('seed-redgum-aquatic-leisure-centre','2.1','2.1','completed','needs-work','{"doingWell":["Is the path from accessible parking to the entrance smooth and level?","Is there directional signage on the road approach directing visitors to accessible parking?","Is there wayfinding signage from the parking area to the entrance?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Accessible parking spaces exist but may not fully comply. Audit each space against AS/NZS 2890.6 for correct dimensions (min 2400mm wide, 5400mm long with shared area), signage, and surface condition.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"The drop-off zone is partially level but has uneven areas or a gap to the footpath. Address remaining level changes with kerb ramps (max 1:8 gradient per AS 1428.1) and ensure the transfer area surface is firm and slip-resistant.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":["Is the parking area itself well-lit?","During busy periods, special events or temporary setups, are accessible parking spaces still available and not blocked?"],"professionalReview":[]}'::jsonb,now() - interval '37 days',now() - interval '35 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
