  values (v_org,v_site,'2.1','2.1','seed-run-redgum-aquatic-leisure-centre-2.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','mixed','{"doingWell":["Is there a drop-off zone near the entrance for customers who need it?","Is the path from accessible parking to the entrance smooth and level?","Is there directional signage on the road approach directing visitors to accessible parking?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Accessible parking spaces exist but may not fully comply. Audit each space against AS/NZS 2890.6 for correct dimensions (min 2400mm wide, 5400mm long with shared area), signage, and surface condition.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Some accessible spaces are close to the entrance but others are not. Review the layout and prioritise relocating any distant spaces to minimise the travel distance to the main entrance.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"The path meets minimum width in some sections but narrows at pinch points. Identify all constrictions and widen to at least 1000mm clear. Provide 1800mm passing spaces at regular intervals along longer paths.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6a","questionText":"Is there wayfinding signage from the parking area to the entrance?","action":"Wayfinding is partially in place but has gaps. Walk the route from each accessible bay to the entrance and add signage at every decision point or change of direction where the next sign is not already visible.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":["Is the drop-off zone level and easy to access from the footpath?","Is the parking area itself well-lit?","During busy periods, special events or temporary setups, are accessible parking spaces still available and not blocked?"],"professionalReview":[]}'::jsonb,'[{"questionId":"2.1-F-1","answer":"partially","partialDescription":"Staff had training in 2023; a refresher is scheduled but not yet booked.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-2","answer":"partially","partialDescription":"Staff had training in 2023; a refresher is scheduled but not yet booked.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3a","answer":"unable-to-check","notes":"Not sure this has been checked since the last refurbishment.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-4","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-5","answer":"partially","partialDescription":"Accessible toilet available but the change table is not adult-sized.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6","answer":"yes","notes":"Verified with the venue coordinator.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6a","answer":"partially","partialDescription":"Ramp at the main entrance but the side entrance still has a single step.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6b","answer":"yes","notes":"Confirmed on site during the March access walk-through.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-7","answer":"yes","notes":"Verified with the venue coordinator.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-8","answer":"unable-to-check","notes":"Awaiting sign-off from the venue coordinator before we can confirm.","times