  on conflict (run_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','2.2','2.2','completed','mixed','{"doingWell":["If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?","Does the ramp feel too steep for someone using a wheelchair or walking frame?"],"priorityActions":[{"questionId":"2.2-D-24","questionText":"Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","action":"Nosing strips are installed on some steps but not all, or contrast is insufficient. Apply compliant strips to every step edge and verify luminance contrast meets the 30% minimum using a contrast meter or approved calculator.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-25","questionText":"Are the stair or step risers enclosed (no open gaps between steps)?","action":"Some risers are enclosed but others remain open. Retrofit riser panels on all remaining open risers to eliminate the catch hazard across the full staircase.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-27","questionText":"If there is a ramp, does it have handrails on both sides?","action":"A handrail exists on one side but is missing on the other. Install a second handrail and verify both meet AS 1428.1 for height (865-1000mm), extension (300mm), and graspable profile.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-30","questionText":"Is the ramp surface slip-resistant in both wet and dry conditions?","action":"The ramp surface is slip-resistant in dry conditions but may be slippery when wet. Test the surface when wet and apply anti-slip treatment or overlay if traction is inadequate. Pay particular attention to the top and bottom transitions.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":["Are entrance mats and surface changes flush and secure?"],"professionalReview":[]}'::jsonb,now() - interval '36 days',now() - interval '34 days',v_org,v_site,v_user,v_user)
