  values ('seed-redgum-aquatic-leisure-centre','2.3','2.3','completed','mixed','{"doingWell":["Is there enough clear space on both sides of internal doors for someone using a wheelchair or mobility aid to approach and open them?","Do floor surfaces and internal doors contrast with walls to help people with low vision orient themselves?","Is there clear wayfinding signage to key destinations within your venue (toilets, lifts, service areas)?"],"priorityActions":[{"questionId":"2.3-1-1","questionText":"Are main circulation paths at least 1 metre wide?","action":"Some paths are wide enough. Survey all routes to key facilities and remove or relocate obstructions (displays, furniture, signage) that narrow paths below 1000mm.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.3-1-2","questionText":"Are paths kept clear of obstacles and trip hazards (e.g., bins, plant pots, or furniture)?","action":"Conduct a walk-through audit to identify and remove all obstacles, protruding objects, and trip hazards from circulation paths, including temporary items like bins, signage, and stock.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.3-D-20","questionText":"Is there at least 2 metres of overhead clearance along all paths?","action":"Ensure a minimum 2000mm overhead clearance along all accessible paths per AS 1428.1 Cl 7. Remove, raise, or guard any low-hanging signs, light fittings, ducts, or branches. Where an overhead hazard cannot be removed, install a detectable barrier (cane-detectable at max 680mm height) beneath it.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.3-D-21","questionText":"Is there enough space for two people to pass each other, or for a wheelchair to turn around?","action":"Widen internal paths to at least 1000mm continuous clear width, with 1800mm passing spaces where two wheelchairs may need to pass, and a 2070mm diameter turning circle at key junctions per AS 1428.1 Cl 7. Rearrange furniture or displays if needed.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '35 days',now() - interval '33 days',v_org,v_site,v_user,v_user)
