  -- ===== Botanic Gardens & Playground =====
  select id into v_site from sites where organisation_id = v_org and name = 'Botanic Gardens & Playground';
  values ('seed-redgum-botanic-gardens-playground','2.1','2.1','completed','mixed','{"doingWell":["Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?","Is the drop-off zone level and easy to access from the footpath?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-7","questionText":"Do staff know how to direct customers to accessible parking and entry points?","action":"Some staff are aware but knowledge is inconsistent. Standardise training so all customer-facing staff can confidently direct visitors to accessible parking and entry points. Consider a printed quick-reference card for new team members.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-8","questionText":"Is the parking area itself well-lit?","action":"Lighting is adequate in some areas but has dark spots. Conduct an after-dark walkthrough from each accessible bay to the entrance and address any poorly lit sections, especially at kerb ramps and direction changes.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":["Is there wayfinding signage from the parking area to the entrance?","If the accessible route differs from the main pedestrian path, is it clearly signed?"],"professionalReview":[]}'::jsonb,now() - interval '31 days',now() - interval '29 days',v_org,v_site,v_user,v_user)
