  values ('seed-redgum-botanic-gardens-playground','2.3','2.3','completed','strong','{"doingWell":["Are main circulation paths at least 1 metre wide?","Is there at least 2 metres of overhead clearance along all paths?","Is there enough space for two people to pass each other, or for a wheelchair to turn around?"],"priorityActions":[{"questionId":"2.3-D-5","questionText":"Is there clear wayfinding signage to key destinations within your venue (toilets, lifts, service areas)?","action":"Some wayfinding signage exists but does not cover all key destinations. Add signs for any unaddressed destinations and ensure the signage system is consistent in style, height, and placement across the venue.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"2.3-D-7","questionText":"For larger or complex venues, is there a floor plan or site map available to visitors?","action":"A floor plan exists but may not be accessible (too small, low contrast, or missing accessible route information). Update it with clear labelling of accessible features and provide it in multiple formats (print, digital, and tactile if feasible).","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":["Are paths kept clear of obstacles and trip hazards (e.g., bins, plant pots, or furniture)?"],"professionalReview":[]}'::jsonb,now() - interval '30 days',now() - interval '28 days',v_org,v_site,v_user,v_user)
