  values ('seed-redgum-botanic-gardens-playground','3.5','3.5','completed','mixed','{"doingWell":["Is signage clear, with good contrast and readable font sizes?","Are signs placed at consistent heights and locations?","Is there directional signage at key decision points throughout the venue?"],"priorityActions":[{"questionId":"3.5-1-3","questionText":"Are accessible facilities (toilets, lifts) clearly signed?","action":"Install clear directional signage to all accessible facilities (toilets, lifts, parking, entrances) using the International Symbol of Access, tactile lettering, and Braille per AS 1428.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-4","questionText":"Would a first-time visitor be able to navigate independently?","action":"Navigation is mostly intuitive. Test with someone unfamiliar with the venue and address the specific points where they hesitate or go the wrong way.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"3.5-D-6","questionText":"Are emergency exit signs clearly visible and illuminated?","action":"Install illuminated emergency exit signs per AS 2293 at all exits and along escape routes. Signs must be visible from the accessible path of travel, include the running-person pictogram, and remain lit during power failure with battery backup.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '29 days',now() - interval '27 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
