  values ('seed-redgum-botanic-gardens-playground','4.1','4.1','completed','mixed','{"doingWell":["Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","Are your staff trained to receive calls via the National Relay Service (NRS)?","Are staff trained to communicate patiently with people who have speech disabilities, strong accents, or use AAC devices?"],"priorityActions":[{"questionId":"4.1-PC-3","questionText":"Do you capture and use customer communication preferences (preferred contact method, format needs)?","action":"You capture some preferences. Ensure the system covers contact method, document format, and language needs, and that preferences are applied consistently across all touchpoints.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-4","questionText":"Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","action":"Set and enforce equivalent service-level agreements for non-phone channels. If phone calls are answered within 2 minutes, email and chat should receive responses within the same window.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-7","questionText":"Is there a quiet space available for communication with customers who need a calmer environment?","action":"Designate a quiet, low-stimulus space where staff can have conversations with customers who need a calmer environment. This could be a private office, meeting room, or screened area.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-8","questionText":"Do you offer written confirmation or follow-up after important phone or in-person conversations?","action":"Offer written confirmation (email, SMS, or letter) after important phone or in-person conversations covering bookings, service changes, or access arrangements.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Are phone alternatives as prominently displayed as your phone number on your website and materials?"],"professionalReview":[]}'::jsonb,now() - interval '28 days',now() - interval '26 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Winter Markets =====
  select id into v_site from sites where organisation_id = v_org and name = 'Winter Markets';
  values ('seed-redgum-winter-markets','1.1','1.1','completed','mixed','{"doingWell":["Is your accessibility information consistent across all platforms?","Do you clearly state limitations or barriers that still exist?","Do you invite feedback about the accuracy of your accessibility information?"],"priorityActions":[{"questionId":"1.1-F-1","questionText":"Do you have accessibility information available for customers before they visit?","action":"Create and publish accessibility information for customers before they visit. Include physical access details, sensory environment descriptions, and available supports. This is a key expectation under the DDA 1992.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-F-6","questionText":"Do staff know how to confidently respond to accessibility enquiries?","action":"Prepare a reference guide of common accessibility enquiries and accurate answers so staff can respond confidently. Include details like accessible parking location, entrance type, available supports, and who to escalate to when unsure.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-F-8","questionText":"Do you provide information about accessible transport options to reach your venue?","action":"Add accessible transport information to your pre-visit materials. Include nearest accessible public transport stops, taxi and rideshare drop-off options, and walking route details from transport stops to your entrance. Parking and drop-off zones are covered separately.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-D-8b","questionText":"Does your transport information describe the ''last 50 metres'' of the journey?","action":"Enhance your last-50-metre information with additional detail about surface conditions, gradients, and any obstacles between transport stops/parking and your entrance.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '27 days',now() - interval '25 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','2.1','2.1','completed','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Is there a drop-off zone near the entrance for customers who need it?","Is the drop-off zone level and easy to access from the footpath?"],"priorityActions":[{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Some accessible spaces are close to the entrance but others are not. Review the layout and prioritise relocating any distant spaces to minimise the travel distance to the main entrance.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"The path is mostly smooth but has uneven sections or minor level changes. Identify and remediate all trip hazards, cracks, or loose surfaces. Ensure the entire route meets AS 1428.1 requirements for a continuous accessible path.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"The path meets minimum width in some sections but narrows at pinch points. Identify all constrictions and widen to at least 1000mm clear. Provide 1800mm passing spaces at regular intervals along longer paths.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-7","questionText":"Do staff know how to direct customers to accessible parking and entry points?","action":"Train all customer-facing staff on the location of accessible parking, the accessible entry route, and how to provide clear directions. Include this in induction and refresher training. Provide a simple reference map at reception.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '26 days',now() - interval '24 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values (v_org,v_site,'2.1','2.1','seed-run-redgum-winter-markets-2.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?"],"priorityActions":[{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"The drop-off zone is partially level but has uneven areas or a gap to the footpath. Address remaining level changes with kerb ramps (max 1:8 gradient per AS 1428.1) and ensure the transfer area surface is firm and slip-resistant.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"The path is mostly smooth but has uneven sections or minor level changes. Identify and remediate all trip hazards, cracks, or loose surfaces. Ensure the entire route meets AS 1428.1 requirements for a continuous accessible path.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"Widen the path to at least 1000mm clear width (1200mm preferred, 1800mm at passing points) per AS 1428.1 Cl 7. Remove any obstructions that narrow the effective width, including overhanging vegetation, bins, or signage.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6a","questionText":"Is there wayfinding signage from the parking area to the entrance?","action":"Wayfinding is partially in place but has gaps. Walk the route from each accessible bay to the entrance and add signage at every decision point or change of direction where the next sign is not already visible.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,'[{"questionId":"2.1-F-1","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-2","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3","answer":"yes","notes":"Confirmed on site during the March access walk-through.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3a","answer":"partially","partialDescription":"Accessibility information is on the website but scattered across a few pages rather than one place.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-4","answer":"partially","partialDescription":"Accessible toilet available but the change table is not adult-sized.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-5","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6a","answer":"partially","partialDescription":"Hearing loop installed at the main desk only, not in meeting rooms.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6b","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-7","answer":"partially","partialDescription":"Signage is clear at the entry but wayfinding inside is inconsistent.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-8","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"}]'::jsonb,v_user)
  on conflict (run_id) do nothing;
  values ('seed-redgum-winter-markets','2.4','2.4','completed','needs-work','{"doingWell":["Is information about queuing and busy periods available before visitors arrive?"],"priorityActions":[{"questionId":"2.4-1-1","questionText":"Is there seating available in queue areas for people who cannot stand for long?","action":"Install or provide portable seating in queue areas for people who cannot stand for extended periods, positioned so they can maintain their place in the queue.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-2a","questionText":"Is there a streamlined or dedicated accessible entry option that bypasses the main queue?","action":"Create a streamlined accessible entry pathway that bypasses the main queue, with clear signage and staff awareness so customers can use it independently.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-3","questionText":"Do staff know how to accommodate customers who need queue assistance?","action":"Some staff are aware. Extend training to all customer-facing roles and include scenarios for different disability types in the training materials.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"2.4-D-4","questionText":"Is the queue layout accessible for wheelchair users and people with mobility aids?","action":"Redesign the queue layout to provide at least 1000mm clear width throughout, a 2070mm turning circle at the service point, and no barriers that impede wheelchairs (e.g., narrow stanchion spacing, high rope barriers). Ensure the queue path is level with a firm surface.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Can customers request priority access when needed?","Is there signage indicating that queue assistance is available for those who need it?"],"professionalReview":[]}'::jsonb,now() - interval '25 days',now() - interval '23 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','3.5','3.5','completed','strong','{"doingWell":["Is signage clear, with good contrast and readable font sizes?","Are accessible facilities (toilets, lifts) clearly signed?","Would a first-time visitor be able to navigate independently?"],"priorityActions":[{"questionId":"3.5-1-2","questionText":"Are signs placed at consistent heights and locations?","action":"Standardise sign mounting heights between 1200mm and 1600mm (eye level range per AS 1428.1) and place signs consistently on the same side of doorways throughout the venue.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '24 days',now() - interval '22 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','4.2','4.2','completed','mixed','{"doingWell":["Do staff feel confident communicating with customers who have different needs?","Do staff know where accessible facilities are located to direct customers?","Do staff know how to communicate with customers who are Deaf or hard of hearing?"],"priorityActions":[{"questionId":"4.2-F-2","questionText":"Do staff know how to welcome and assist customers with assistance animals?","action":"Some staff are aware. Ensure all staff (including casuals and contractors) know that assistance animals must be admitted, cannot be questioned, and must not be separated from their handler.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"4.2-F-4","questionText":"Do you have a process for customers to request assistance before arriving?","action":"A process exists but may not be well promoted or consistently actioned. Ensure the request option is visible in all booking channels and that requests are acknowledged and fulfilled.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-5","questionText":"Are staff trained in various communication strategies?","action":"Some strategies are known. Broaden training to cover signing basics (at minimum, greeting in Auslan), written communication, visual supports, and techniques for communicating with people who have cognitive disabilities.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-7","questionText":"Is there a clear process for handling accessibility complaints or feedback?","action":"Document a clear process for handling accessibility complaints and feedback. Include who receives them, response timeframes, escalation paths, and how outcomes are communicated back to the customer.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you have a documented policy on serving customers with disabilities?"],"professionalReview":[]}'::jsonb,now() - interval '23 days',now() - interval '21 days',v_org,v_site,v_user,v_user)
