  -- ===== Riverbend Summer Festival =====
  select id into v_site from sites where organisation_id = v_org and name = 'Riverbend Summer Festival';
  values ('seed-redgum-riverbend-summer-festival','1.1','1.1','completed','mixed','{"doingWell":["Do you invite feedback about the accuracy of your accessibility information?","Do staff know how to confidently respond to accessibility enquiries?","Do you provide information about accessible transport options to reach your venue?"],"priorityActions":[{"questionId":"1.1-F-1","questionText":"Do you have accessibility information available for customers before they visit?","action":"Review your current accessibility information for completeness. Ensure it covers physical access, sensory environment, communication supports, and practical visit-planning details.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-F-5","questionText":"Can customers contact you in a variety of ways to ask accessibility questions before visiting?","action":"Provide multiple ways for customers to ask accessibility questions before visiting, such as phone, email, online chat, contact form, and social media messaging. Relying on a single channel excludes customers who cannot use that method.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-D-5b","questionText":"Do customers have a way to ask accessibility questions without calling?","action":"Review your non-phone contact options to ensure they are genuinely accessible and responsive. Confirm that enquiries via these channels receive the same quality and speed of response as phone calls.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":["Is your accessibility information consistent across all platforms?","Do you proactively invite accessibility questions?"],"professionalReview":[]}'::jsonb,now() - interval '22 days',now() - interval '20 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','1.4','1.4','completed','needs-work','{"doingWell":["Do you include alt text or image descriptions when posting images on social media?","Do you add alt text or image descriptions to each image in carousel or multi-image posts?","Do you verify that alt text is preserved when reposting or sharing content?"],"priorityActions":[{"questionId":"1.4-PC-4","questionText":"Can users control video playback using keyboard, screen readers, or other assistive technology?","action":"Ensure all video players on your website support keyboard controls and are compatible with screen readers and other assistive technology, per WCAG 2.2 Success Criterion 2.1.1 (Keyboard). Users must be able to play, pause, adjust volume, and toggle captions without a mouse.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-6","questionText":"Does your video and social media content include diverse representation, including people with disability?","action":"Include authentic representation of people with disability in your video and social media content. Feature people with visible and non-visible disabilities as customers, participants, and community members, not just in accessibility-specific contexts.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.4-DD-1d","questionText":"Are captions easy to read (good contrast, appropriate size, clear font)?","action":"Review caption readability across your video content. Test captions on different devices and screen sizes to ensure they remain legible.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.4-DD-3e","questionText":"When you add text over images, does it have sufficient contrast to be readable?","action":"Ensure text overlaid on images meets the minimum contrast ratio of 4.5:1 for normal text or 3:1 for large text, per WCAG 2.2 Success Criterion 1.4.3 (Contrast - Minimum). Use a semi-transparent background behind text when placed over variable image backgrounds.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":["Do your website and communications use clear, plain language that is easy to understand?"],"professionalReview":[]}'::jsonb,now() - interval '21 days',now() - interval '19 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','2.1','2.1','completed','mixed','{"doingWell":["Are accessible parking spaces located close to the main entrance?","Is the drop-off zone level and easy to access from the footpath?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Accessible parking spaces exist but may not fully comply. Audit each space against AS/NZS 2890.6 for correct dimensions (min 2400mm wide, 5400mm long with shared area), signage, and surface condition.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"A drop-off area exists but may lack clear signage, adequate length, or a direct connection to the accessible path. Review and formalise the zone with appropriate markings and kerb ramps to the footpath.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"The path is mostly smooth but has uneven sections or minor level changes. Identify and remediate all trip hazards, cracks, or loose surfaces. Ensure the entire route meets AS 1428.1 requirements for a continuous accessible path.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-6b","questionText":"If the accessible route differs from the main pedestrian path, is it clearly signed?","action":"Install clear signage at the point where the accessible route diverges from the main pedestrian path. Use the ISA with directional arrows and ensure signs are visible from both directions. Include distance or travel time where helpful.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '20 days',now() - interval '18 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','2.4','2.4','completed','mixed','{"doingWell":["Do you offer alternative queue arrangements (e.g., text notification, numbered tickets)?","Do you communicate expected wait times to customers?","Is information about queuing and busy periods available before visitors arrive?"],"priorityActions":[{"questionId":"2.4-1-1","questionText":"Is there seating available in queue areas for people who cannot stand for long?","action":"Install or provide portable seating in queue areas for people who cannot stand for extended periods, positioned so they can maintain their place in the queue.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-2","questionText":"Can customers request priority access when needed?","action":"Priority access is sometimes offered. Formalise the policy, ensure all staff are trained, and add visible signage so customers know they can request it.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-2a","questionText":"Is there a streamlined or dedicated accessible entry option that bypasses the main queue?","action":"Create a streamlined accessible entry pathway that bypasses the main queue, with clear signage and staff awareness so customers can use it independently.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-3","questionText":"Do staff know how to accommodate customers who need queue assistance?","action":"Some staff are aware. Extend training to all customer-facing roles and include scenarios for different disability types in the training materials.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '19 days',now() - interval '17 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
