  values ('seed-redgum-riverbend-summer-festival','3.6','3.6','completed','mixed','{"doingWell":["Are large print versions of key materials available?","Is pricing information displayed in a way that is easy to read and locate?"],"priorityActions":[{"questionId":"3.6-1-3","questionText":"Are digital alternatives available (QR codes, online menus)?","action":"Some digital options exist. Verify QR codes link to accessible content (not just a PDF image) and that digital menus work with screen readers.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"3.6-D-2","questionText":"Are your QR codes large enough and well-positioned?","action":"Some QR codes are well-positioned but others are not. Audit placements for height, size, contrast, and reachability from a wheelchair, and reposition any that are inaccessible.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":["Can staff read menus or materials aloud for customers who need it?"],"professionalReview":[]}'::jsonb,now() - interval '18 days',now() - interval '16 days',v_org,v_site,v_user,v_user)
