  values ('seed-redgum-riverbend-summer-festival','4.2','4.2','completed','mixed','{"doingWell":["Do staff feel confident communicating with customers who have different needs?","Do you have a process for customers to request assistance before arriving?","Is pen and paper available for written communication if needed?"],"priorityActions":[{"questionId":"4.2-F-2","questionText":"Do staff know how to welcome and assist customers with assistance animals?","action":"Train all staff on assistance animal rights under the Disability Discrimination Act 1992. Staff must know they cannot refuse entry, request proof of disability, or charge extra for assistance animals.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.2-F-5","questionText":"Are staff trained in various communication strategies?","action":"Some strategies are known. Broaden training to cover signing basics (at minimum, greeting in Auslan), written communication, visual supports, and techniques for communicating with people who have cognitive disabilities.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-7","questionText":"Is there a clear process for handling accessibility complaints or feedback?","action":"Document a clear process for handling accessibility complaints and feedback. Include who receives them, response timeframes, escalation paths, and how outcomes are communicated back to the customer.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '17 days',now() - interval '15 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
