  values ('seed-redgum-riverbend-summer-festival','4.7','4.7','completed','mixed','{"doingWell":["Are your written communications (letters, emails, invoices) designed to be clear and accessible?","Are your emails designed for accessibility (readable without images, proper headings, plain text option)?","Are your PDF documents and attachments created accessibly (tagged, proper headings, alt text)?"],"priorityActions":[{"questionId":"4.7-PC-4","questionText":"Do you have accessible email templates that staff use for customer communications?","action":"Create accessible email templates for common customer communications (booking confirmations, receipts, newsletters, service updates). Include proper heading structure, alt text placeholders, high-contrast design, and meaningful link text.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-PC-8","questionText":"Are your mailing lists and subscription options accessible (email preferences, unsubscribe options)?","action":"The process is partially accessible. Test the full journey (subscribe, manage preferences, unsubscribe) with a screen reader and keyboard-only navigation. Fix any barriers to independent use.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.7-DD-2a","questionText":"Have you tested your emails for accessibility (screen reader, images disabled)?","action":"Test your customer emails for accessibility: use a screen reader (NVDA or VoiceOver) to read the email, disable images to check content is still understandable, verify keyboard navigation, and check colour contrast. Test on both desktop and mobile.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do staff who create documents know how to use heading styles, alt text, and proper structure?","Can your systems automatically apply customer preferences (e.g., send large print version to customers who need it)?"],"professionalReview":[]}'::jsonb,now() - interval '16 days',now() - interval '14 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Town Hall & Civic Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Town Hall & Civic Centre';
  values ('seed-redgum-town-hall-civic-centre','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Is your accessibility information consistent across all platforms?","Is your transport information specific to accessibility needs?"],"priorityActions":[{"questionId":"1.1-D-11","questionText":"Do you invite feedback about the accuracy of your accessibility information?","action":"Strengthen your feedback invitation by making it more prominent and specifying how customer input will be used to improve your accessibility information.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.1-D-5c","questionText":"Do you proactively invite accessibility questions?","action":"Increase the visibility and frequency of your invitation for accessibility questions. Include prompts at key touchpoints such as booking confirmation, pre-visit emails, and your contact page.","priority":"medium","timeframe":"90-180 days"},{"questionId":"1.1-F-8","questionText":"Do you provide information about accessible transport options to reach your venue?","action":"Expand your transport information with more specific details about each option: which bus/train stops have step-free access, typical distances to your entrance, and surface conditions on walking routes.","priority":"medium","timeframe":"90-180 days"}],"areasToExplore":["Do you clearly state limitations or barriers that still exist?","Can customers contact you in a variety of ways to ask accessibility questions before visiting?","Do customers have a way to ask accessibility questions without calling?"],"professionalReview":[]}'::jsonb,now() - interval '15 days',now() - interval '13 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','2.1','2.1','completed','strong','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is the drop-off zone level and easy to access from the footpath?"],"priorityActions":[{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-6b","questionText":"If the accessible route differs from the main pedestrian path, is it clearly signed?","action":"Some signage exists but the divergence point is not clearly marked. Add prominent ISA signage at the exact point of divergence and at intervals along the alternative route until it reaches the entrance.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '14 days',now() - interval '12 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','2.2','2.2','completed','strong','{"doingWell":["Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","Are the stair or step risers enclosed (no open gaps between steps)?","Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?"],"priorityActions":[{"questionId":"2.2-D-23","questionText":"If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","action":"Handrails are present but may be on one side only or not fully compliant. Install a second handrail where missing and check that both meet AS 1428.1 for height, extension, graspability, and continuity.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-31","questionText":"Is the entrance lift large enough for a wheelchair user, with at least a 900mm door opening?","action":"The lift partially meets requirements but may fall short on door width or internal dimensions. Measure against AS 1735.12 minimums (900mm door, 1400 x 1100mm cabin) and plan modifications for any non-compliant dimension.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-18","questionText":"Are entrance mats and surface changes flush and secure?","action":"Mats are mostly secure but some edges lift or the frame is slightly raised. Re-secure or replace problem mats. Choose thin, firm-pile mats in flush recessed frames. Check after cleaning that mats are re-seated properly.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '13 days',now() - interval '11 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','3.1','3.1','completed','strong','{"doingWell":["Are tables and counters at accessible heights for wheelchair users?","Can furniture be rearranged to accommodate different needs?","Are aisles and pathways between furniture wide enough throughout the space?"],"priorityActions":[{"questionId":"3.1-1-1","questionText":"Is there a variety of seating options (with arms, without arms, different heights)?","action":"Provide seating with different arm, height, and depth options so people with varying mobility, size, and support needs can find comfortable seating.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-1-2","questionText":"Is there space for wheelchair users alongside seated companions?","action":"Some wheelchair spaces exist. Verify they are distributed across different areas and price points, not clustered in one location with poor sightlines.","priority":"high","timeframe":"90-180 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '12 days',now() - interval '10 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','4.2','4.2','completed','mixed','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do staff feel confident communicating with customers who have different needs?","Are staff trained in various communication strategies?"],"priorityActions":[{"questionId":"4.2-F-4","questionText":"Do you have a process for customers to request assistance before arriving?","action":"Create a process for customers to request assistance before arriving. Include it in your booking flow, on your website contact page, and in booking confirmations. Nominate a staff member to action requests.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-7","questionText":"Is there a clear process for handling accessibility complaints or feedback?","action":"A process exists but may not be well documented or consistently followed. Formalise it in writing, train all staff, and ensure customers are informed of expected response times.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-11","questionText":"Is pen and paper available for written communication if needed?","action":"Materials are available in some locations. Ensure every customer service point, reception, and counter has writing materials readily accessible without customers needing to ask.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-12","questionText":"Do staff know how to assist customers who may need extra time or have cognitive differences?","action":"Staff are generally patient. Formalise training on cognitive accessibility techniques: chunking information, using visual supports, checking understanding without being patronising, and allowing processing time.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":["Are staff trained to offer assistance without being condescending or over-helpful?","Do staff know how to communicate with customers who are Deaf or hard of hearing?"],"professionalReview":[]}'::jsonb,now() - interval '11 days',now() - interval '9 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.1','5.1','completed','needs-work','{"doingWell":["Is accessibility considered in your marketing and communications strategy?"],"priorityActions":[],"areasToExplore":["Do you track and report on accessibility improvements?"],"professionalReview":[]}'::jsonb,now() - interval '10 days',now() - interval '8 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.3','5.3','completed','mixed','{"doingWell":["Is disability awareness included in staff onboarding?","Do staff know who to contact if they need advice on accessibility?"],"priorityActions":[{"questionId":"5.3-D-1","questionText":"Is disability training refreshed regularly?","action":"Some refresher training occurs but may not be consistent. Establish a formal schedule (at least annual) for all staff, track completion rates, and update content to reflect current best practice and any changes to your services.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"},{"questionId":"5.3-D-3","questionText":"Do staff have access to resources about accessibility and disability?","action":"Some resources are available. Consolidate them into a single, easy-to-find location. Include practical guides, your accessibility policy, equipment instructions, and links to external resources such as JobAccess, AHRC, and IncludeAbility.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '9 days',now() - interval '7 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.5','5.5','completed','mixed','{"doingWell":["Do you set accessibility improvement goals?","Do you track accessibility-related metrics or KPIs?"],"priorityActions":[{"questionId":"5.5-D-9","questionText":"Do you celebrate accessibility achievements and recognise staff contributions?","action":"Some recognition occurs informally. Formalise it through regular internal communications highlighting progress, awards or recognition programs, and inclusion of accessibility achievements in performance reviews.","priority":"medium","timeframe":"90-180 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '8 days',now() - interval '6 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

